const {Storage} = require('@google-cloud/storage');

const storage = new Storage();

/**
 * Serves files from Cloud Storage based on HTTP request query parameters.
 *
 * @param {object} req The HTTP request object.
 * @param {object} res The HTTP response object.
 */
exports.serveStorageFile = async (req, res) => {
  const bucketName = req.query.bucket;
  const filePath = req.query.filePath;

  if (!bucketName || !filePath) {
    res.status(400).send('Missing "bucket" or "filePath" query parameter.');
    return;
  }

  const bucket = storage.bucket(bucketName);
  const file = bucket.file(filePath);

  try {
    const [exists] = await file.exists();

    if (!exists) {
      res.status(404).send(`File not found: gs://${bucketName}/${filePath}`);
      return;
    }

    // Guess content type based on file extension
    const mime = require('mime-types');
    const contentType = mime.lookup(filePath) || 'application/octet-stream';
    res.set('Content-Type', contentType);

    // Stream the file directly to the response
    file.createReadStream()
      .on('error', (err) => {
        console.error(`Error streaming file gs://${bucketName}/${filePath}:`, err);
        res.status(500).send('Error streaming file.');
      })
      .pipe(res);

  } catch (error) {
    console.error(`Error accessing file gs://${bucketName}/${filePath}:`, error);
    // Differentiate between permissions errors and other issues if needed
    if (error.code === 403) {
      res.status(403).send('Permission denied to access this file.');
    } else if (error.code === 404) { // This might be redundant due to file.exists() check
      res.status(404).send(`File not found: gs://${bucketName}/${filePath}`);
    } else {
      res.status(500).send('An unexpected error occurred.');
    }
  }
};